import{_ as l,o as r,c as t,a2 as e}from"./chunks/framework.Crpw6aS5.js";const c=JSON.parse('{"title":"Marmon集团","description":"","frontmatter":{"title":"Marmon集团"},"headers":[],"relativePath":"03_companies/Marmon集团.md","filePath":"03_companies/Marmon集团.md"}'),i={name:"03_companies/Marmon集团.md"};function o(n,a,s,h,m,_){return r(),t("div",null,[...a[0]||(a[0]=[e('<h1 id="marmon集团" tabindex="-1">Marmon集团 <a class="header-anchor" href="#marmon集团" aria-label="Permalink to &quot;Marmon集团&quot;">​</a></h1><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><ul><li><strong>首次提及</strong>: 2007年</li><li><strong>持股情况</strong>: <ul><li>2007年圣诞节收购60%</li><li>约定六年内收购剩余40%</li><li>2008年收购64%股份</li><li>后逐步增持至100%</li></ul></li><li><strong>行业</strong>: 多元化工业集团</li><li><strong>英文名</strong>: Marmon Group</li><li><strong>原拥有者</strong>: 普利兹克家族</li><li><strong>CEO</strong>: 弗兰克·普塔克（Frank Ptak）</li></ul><h2 id="巴菲特论述" tabindex="-1">巴菲特论述 <a class="header-anchor" href="#巴菲特论述" aria-label="Permalink to &quot;巴菲特论述&quot;">​</a></h2><p>2007年圣诞节从普利兹克家族收购60%股权，约定六年内收购剩余40%。Marmon运营125家企业，分为9个部门。</p><p>最大业务联合罐车公司拥有94,000节铁路罐车，是北美最大的罐车租赁商之一。业务范围从铁路车厢租赁到医疗设备制造，拥有100多个独立的业务运营。</p><p>Marmon是伯克希尔&quot;五大非保险业务支柱&quot;之一，代表了巴菲特对多元化工业集团的青睐。这类企业虽然不是明星业务，但产生稳定的现金流，且管理团队出色。</p><h2 id="投资特点" tabindex="-1">投资特点 <a class="header-anchor" href="#投资特点" aria-label="Permalink to &quot;投资特点&quot;">​</a></h2><ul><li>多元化业务降低风险</li><li>大量固定资产提供稳定收益</li><li>专业管理团队</li><li>与伯克希尔其他业务（如BNSF铁路）有协同效应</li></ul><h2 id="关联年份" tabindex="-1">关联年份 <a class="header-anchor" href="#关联年份" aria-label="Permalink to &quot;关联年份&quot;">​</a></h2><p>2007, 2008, 2010, 2021</p><h2 id="相关信件" tabindex="-1">相关信件 <a class="header-anchor" href="#相关信件" aria-label="Permalink to &quot;相关信件&quot;">​</a></h2><ul><li><a href="./../01_letters/2007年/翻译.html">2007年</a></li><li><a href="./../01_letters/2010年/翻译.html">2010年</a></li><li><a href="./../01_letters/2011年/翻译.html">2011年</a></li><li><a href="./../01_letters/2013年/翻译.html">2013年</a></li><li><a href="./../01_letters/2014年/翻译.html">2014年</a></li><li><a href="./../01_letters/2015年/翻译.html">2015年</a></li><li><a href="./../01_letters/2016年/翻译.html">2016年</a></li></ul>',13)])])}const u=l(i,[["render",o]]);export{c as __pageData,u as default};
